interface Iterator<T> { boolean hasNext(); T next(); }
interface Aggregato<T> { Iterator<T> iterator(); }
class ConcreteIterator<T> implements Iterator<T> { private int current; public boolean hasNext(){...} public T next(){...} }

abstract class Creator { abstract Product getProduct(); public void anOperation(){ Product p = getProduct(); p.request(); } }
class ConcreteCreator extends Creator { Product getProduct(){ return new ConcreteProduct(); } }
Ruoli UML: Creator -> Product; ConcreteCreator crea ConcreteProduct.

interface StyleFactory { Window createWindow(); Menu createMenu(); Button createButton(); }
class MacStyleFactory implements StyleFactory { ... }
class WinStyleFactory implements StyleFactory { ... }
Client usa solo factory e prodotti astratti.

interface Prototype { Prototype clone(); }
class Shape implements Cloneable { public Shape clone(){ ... } }
class PrototypeManager { Prototype get(String key){ return prototypes.get(key); } }

interface Target { String request(); }
class Adapter implements Target { private Adaptee adaptee; public String request(){ return adaptee.specificRequest(); } }
Client -> Target; Adapter implementa Target e delega ad Adaptee.

interface Strategy { String apply(int x); }
class Context { public void executeTask(Strategy s){ s.apply(data); } }
Esempi: Comparator<Player> byAge/byRanking; lambda e method reference possono essere strategie.

abstract class Node { abstract void accept(Visitor v); }
class BinaryTreeNode extends Node { void accept(Visitor v){ v.visitBinaryTreeNode(this); } }
interface Visitor { void visitBinaryTreeNode(BinaryTreeNode n); void visitBinaryTreeLeaf(BinaryTreeLeaf l); }

interface Component { void operation(); }
class Decorator implements Component { private final Component next; public void operation(){ next.operation(); } }
class BorderDecorator extends Decorator { public void operation(){ super.operation(); drawBorder(); } }

abstract class Command { abstract void execute(); }
class OpenCommand extends Command { private Application receiver; public void execute(){ Document d = new Document(name); receiver.add(d); receiver.open(); } }
class Menu { Map<String,Command> actions; void handleEvent(String label){ actions.get(label).execute(); } }

interface Mediator { void doWork(Colleague c); }
class CoolingMediator implements Mediator { Button button; Fan fan; PowerSupply power; public void doWork(Button b){ power.turnOn(); fan.turnOn(); } }
I colleague comunicano col mediator.

