 * Esercizio 10: Data una lista di dipendenti con progetti, 
 * trovare tutti i dipendenti che lavorano su progetti con scadenza entro il mese corrente.
 */

public class Casa10 {
 public static void main(String[] args) {
 List<Dipendente> dipendenti = List.of(
 new Dipendente("Mario Rossi", "IT", List.of(
 new Progetto("Progetto A", LocalDate.of(2024, 12, 15), "Alta"),
 new Progetto("Progetto B", LocalDate.of(2025, 6, 10), "Media")
 )),
 new Dipendente("Giulia Bianchi", "Marketing", List.of(
 new Progetto("Progetto C", LocalDate.of(2024, 12, 25), "Bassa"),
 new Progetto("Progetto D", LocalDate.of(2025, 1, 5), "Alta")
 )),
 new Dipendente("Luca Verdi", "HR", List.of(
 new Progetto("Progetto E", LocalDate.of(2024, 11, 30), "Media")
 ))
 );
 LocalDate last_month = LocalDate.of(2025, 6, 6);
 List<Dipendente> projects_due_this_month = dipendenti.stream()
 .filter(x -> x.progetti().stream()
 .anyMatch(project -> project.scadenza().isAfter(last_month)) 
 )
 .toList();

 for (Dipendente dipendente : projects_due_this_month) {
 System.out.print(dipendente.nome() + " | ");
 }
 }
