import java.time.LocalDate;
import java.util.List;
import java.util.stream.Collectors;

/*
 * Esercizio 13: Data una lista di transazioni bancarie, calcolare il saldo finale per ogni conto.
 */

public class Casa13 {
 public static void main(String[] args) {
 List<Transazione> transazioni = List.of(
 new Transazione("IT123456", 1000.0, "ENTRATA", LocalDate.of(2024, 1, 15)),
 new Transazione("IT123456", 200.0, "USCITA", LocalDate.of(2024, 1, 16)),
 new Transazione("IT789012", 500.0, "ENTRATA", LocalDate.of(2024, 1, 17)),
 new Transazione("IT123456", 150.0, "USCITA", LocalDate.of(2024, 1, 18)),
 new Transazione("IT789012", 75.0, "USCITA", LocalDate.of(2024, 1, 19)),
 new Transazione("IT345678", 800.0, "ENTRATA", LocalDate.of(2024, 1, 20)),
 new Transazione("IT123456", 300.0, "ENTRATA", LocalDate.of(2024, 1, 21)),
 new Transazione("IT345678", 100.0, "USCITA", LocalDate.of(2024, 1, 22))
 );

 var saldiFinali = transazioni.stream()
 .collect(Collectors.groupingBy(
 Transazione::conto,
 Collectors.summingDouble(t -> 
 t.tipo().equals("ENTRATA") ? t.importo() : -t.importo())
 ));

 saldiFinali.forEach((conto, saldo) -> 
 System.out.println("Conto: " + conto + ", Saldo: " + saldo));
 }
}

record Transazione(String conto, double importo, String tipo, LocalDate data) {
 // tipo può essere "ENTRATA" o "USCITA"
}
